def process(wine_data) -> pd.DataFrame:
    # Categorize wines into quality groups for better analysis
    def categorize_quality(q):
        if q <= 4:
            return 'Low'
        elif q <= 6:
            return 'Medium'
        else:
            return 'High'

    wine_data['quality_category'] = wine_data['quality'].apply(categorize_quality)
    return wine_data
